#include<bits/stdc++.h>
using namespace std;
vector<pair<long long,long long>> mp[500010];
long long dis[500010],a[500010],n;
bool vis[500010];
void dijkstra(long long x)
{
    memset(dis,0x3f,sizeof(dis));
    memset(vis,0,sizeof(vis));
    dis[x]=0;
    priority_queue<pair<long long,long long>> q;
    q.push(make_pair(0,x));
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
}
long long sum(long long h)
{
    for(long long i=0;i<a[1];i++)
    {
        mp[i].clear();
    }
    for(long long i=0;i<a[1];i++)
    {
        for(long long j=2;j<=n;j++)
        {
            mp[i].push_back(make_pair((i+a[j])%a[1],a[j]));
        }
    }
    dijkstra(0);
    long long ans=0;
    for(long long i=0;i<a[1];i++)
    {
        if(dis[i]<=h)
        {
            ans+=(h-dis[i])/a[1]+1;
        }
    }
    return ans;
}
int main()
{
    long long l,r;
    scanf("%lld%lld%lld",&n,&l,&r);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&a[i]);
    }
    printf("%lld",sum(r)-sum(l-1));
    return 0;
}
